cd "D:/nexgaios-amazon" && PYTHONUTF8=1 python -c "
import pandas as pd, glob, re
base='品牌分析/搜索目录绩效'
main5={'B0DHPN1DMJ','B0CR1R7FKP','B0CLLT85Y6','B0DCZQX11P','B0FNCQW2K3'}
rows=[]
for f in glob.glob(base+'/*.csv'):
    m=re.search(r'(\d{4})_(\d{2})_\d{2}\.csv$',f); ym=f'{m.group(1)}-{m.group(2)}'
    df=pd.read_csv(f,skiprows=1,encoding='utf-8-sig'); c=df.columns.tolist()
    d=df[df[c[1]].isin(main5)]
    def num(x):
        try: return float(str(x).replace(',','').replace('%',''))
        except: return 0.0
    for _,r in d.iterrows():
        rows.append((ym,num(r[c[3]]),num(r[c[9]]),num(r[c[20]])))
a=pd.DataFrame(rows,columns=['ym','imp','clk','ord']).groupby('ym').sum().reset_index().sort_values('ym')
print('own-funnel monthly (5 main ASIN), 2025-02..2026-06:')
for _,r in a.iterrows():
    if r.ym>='2025-02':
        print(f'  {r.ym}: imp={r.imp:>9,.0f} clk={r.clk:>7,.0f} CTR={r.clk/r.imp*100:5.3f}%  CVR(ord/clk)={r.ord/r.clk*100:5.2f}%')
# compare same 4 clean months Apr-Jun + Jan across years for CTR
for yr in ['2025','2026']:
    sub=a[a['ym'].isin([f'{yr}-04',f'{yr}-05',f'{yr}-06'])]
    print(f'{yr} Apr-Jun (clean, no Feb-Mar anomaly): CTR={sub.clk.sum()/sub.imp.sum()*100:.3f}%')
"
